import{_ as a,o as e,c as s,ag as n}from"./chunks/framework.BMy1X8j3.js";const g=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"vercel_ai_docs/guide/getting-started.md","filePath":"vercel_ai_docs/guide/getting-started.md"}'),d={name:"vercel_ai_docs/guide/getting-started.md"};function r(p,t,l,o,i,c){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><blockquote><p>Vercel AI SDK 开源源码学习指南</p></blockquote><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>Vercel AI SDK 是目前最流行的 AI 应用开发框架，不是一个 Agent 产品（如 Claude Code、Codex），而是构建 Agent 的<strong>积木</strong>。它提供 Provider 抽象、流式处理、工具系统、UI 集成等基础设施，让开发者专注于业务逻辑。</p><h2 id="项目统计" tabindex="-1">项目统计 <a class="header-anchor" href="#项目统计" aria-label="Permalink to &quot;项目统计&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>语言</td><td>TypeScript</td></tr><tr><td>核心包</td><td>packages/ai/（~200 源文件）</td></tr><tr><td>Provider 包</td><td>50+（OpenAI、Anthropic、Google、Mistral...）</td></tr><tr><td>UI 框架支持</td><td>React、Vue、Svelte、Angular、Solid</td></tr><tr><td>构建系统</td><td>Turborepo + tsup</td></tr><tr><td>包管理</td><td>pnpm workspace</td></tr><tr><td>许可证</td><td>Apache-2.0</td></tr></tbody></table><h2 id="架构总览" tabindex="-1">架构总览 <a class="header-anchor" href="#架构总览" aria-label="Permalink to &quot;架构总览&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ai/（仓库根目录）</span></span>
<span class="line"><span>├── packages/</span></span>
<span class="line"><span>│   ├── ai/                    ← 核心包（主要学习目标）</span></span>
<span class="line"><span>│   │   └── src/</span></span>
<span class="line"><span>│   │       ├── generate-text/  ← generateText / streamText（Agent Loop）</span></span>
<span class="line"><span>│   │       ├── generate-object/ ← 结构化输出</span></span>
<span class="line"><span>│   │       ├── agent/          ← ToolLoopAgent</span></span>
<span class="line"><span>│   │       ├── middleware/     ← 中间件系统</span></span>
<span class="line"><span>│   │       ├── registry/      ← Provider Registry</span></span>
<span class="line"><span>│   │       ├── prompt/        ← 提示词处理</span></span>
<span class="line"><span>│   │       ├── ui/            ← useChat / useCompletion</span></span>
<span class="line"><span>│   │       ├── ui-message-stream/ ← UIMessageStream</span></span>
<span class="line"><span>│   │       ├── text-stream/   ← 文本流处理</span></span>
<span class="line"><span>│   │       ├── types/         ← 类型定义</span></span>
<span class="line"><span>│   │       ├── error/         ← 错误类型</span></span>
<span class="line"><span>│   │       ├── telemetry/     ← OpenTelemetry</span></span>
<span class="line"><span>│   │       ├── model/         ← 模型版本适配</span></span>
<span class="line"><span>│   │       └── util/          ← 工具函数</span></span>
<span class="line"><span>│   ├── provider/              ← Provider 接口定义</span></span>
<span class="line"><span>│   ├── provider-utils/        ← Provider 工具函数</span></span>
<span class="line"><span>│   ├── openai/                ← OpenAI Provider</span></span>
<span class="line"><span>│   ├── anthropic/             ← Anthropic Provider</span></span>
<span class="line"><span>│   ├── google/                ← Google Provider</span></span>
<span class="line"><span>│   ├── react/                 ← React hooks</span></span>
<span class="line"><span>│   ├── vue/                   ← Vue composables</span></span>
<span class="line"><span>│   ├── svelte/                ← Svelte stores</span></span>
<span class="line"><span>│   ├── mcp/                   ← MCP 协议</span></span>
<span class="line"><span>│   └── ...（50+ providers）</span></span></code></pre></div><h2 id="与-claude-code-codex-的定位差异" tabindex="-1">与 Claude Code / Codex 的定位差异 <a class="header-anchor" href="#与-claude-code-codex-的定位差异" aria-label="Permalink to &quot;与 Claude Code / Codex 的定位差异&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Vercel AI SDK</th><th>Claude Code</th><th>Codex</th></tr></thead><tbody><tr><td>定位</td><td>框架/SDK</td><td>Agent 产品</td><td>Agent 产品</td></tr><tr><td>用户</td><td>开发者（构建 AI 应用）</td><td>开发者（终端编码）</td><td>开发者（终端编码）</td></tr><tr><td>Agent Loop</td><td>提供积木（generateText）</td><td>完整实现（queryLoop）</td><td>完整实现（事件循环）</td></tr><tr><td>上下文压缩</td><td>不提供</td><td>7 层防御</td><td>自动压缩</td></tr><tr><td>记忆系统</td><td>不提供</td><td>CLAUDE.md + Dream Mode</td><td>AGENTS.md</td></tr><tr><td>沙箱</td><td>不提供</td><td>Seatbelt/Bubblewrap</td><td>Landlock/Seatbelt</td></tr><tr><td>Provider 抽象</td><td>最完善（50+ providers）</td><td>单一（Anthropic）</td><td>多个（OpenAI 为主）</td></tr><tr><td>UI 集成</td><td>最完善（5 框架）</td><td>Ink（终端）</td><td>Ratatui（终端）</td></tr></tbody></table><h2 id="核心术语速查" tabindex="-1">核心术语速查 <a class="header-anchor" href="#核心术语速查" aria-label="Permalink to &quot;核心术语速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>含义</th></tr></thead><tbody><tr><td>generateText</td><td>阻塞式 Agent Loop，等待完成后返回</td></tr><tr><td>streamText</td><td>流式 Agent Loop，逐 token 输出</td></tr><tr><td>maxSteps</td><td>Agent Loop 的最大迭代次数（安全阀）</td></tr><tr><td>Provider</td><td>模型提供商的适配器（OpenAI、Anthropic 等）</td></tr><tr><td>LanguageModel</td><td>统一的模型接口（所有 Provider 实现这个接口）</td></tr><tr><td>ToolSet</td><td>工具集合，用 Zod schema 定义参数</td></tr><tr><td>Middleware</td><td>中间件，在模型调用前后插入自定义逻辑</td></tr><tr><td>UIMessageStream</td><td>前端消息流协议</td></tr><tr><td>smoothStream</td><td>流式输出平滑化（避免一次性输出大块文本）</td></tr><tr><td>StepResult</td><td>每一步的结果（包含文本、工具调用、usage）</td></tr></tbody></table><h2 id="推荐阅读顺序" tabindex="-1">推荐阅读顺序 <a class="header-anchor" href="#推荐阅读顺序" aria-label="Permalink to &quot;推荐阅读顺序&quot;">​</a></h2><ol><li><a href="/ai_harness/vercel_ai_docs/agent/generate-text-loop.html">generateText 循环</a> — 理解核心 Agent Loop</li><li><a href="/ai_harness/vercel_ai_docs/provider/language-model-interface.html">LanguageModel 接口</a> — 理解 Provider 抽象</li><li><a href="/ai_harness/vercel_ai_docs/tools/type-safe-tools.html">类型安全工具</a> — 理解工具系统</li><li><a href="/ai_harness/vercel_ai_docs/streaming/web-streams.html">Web Streams 基础</a> — 理解流式处理</li><li><a href="/ai_harness/vercel_ai_docs/middleware/wrap-model.html">wrapLanguageModel</a> — 理解中间件</li><li><a href="/ai_harness/vercel_ai_docs/ui/use-chat.html">useChat</a> — 理解 UI 集成</li></ol>`,14)])])}const u=a(d,[["render",r]]);export{g as __pageData,u as default};
